const item = $input.first();
const form = item.json;

// Read uploaded JSON file
let raw = '';
if (item.binary?.['Workflow JSON']) {
  const buf = await this.helpers.getBinaryDataBuffer(0, 'Workflow JSON');
  raw = buf.toString('utf-8');
} else {
  throw new Error('No workflow JSON file uploaded.');
}

const wf = JSON.parse(raw);
if (!Array.isArray(wf.nodes))           throw new Error('Invalid workflow: nodes must be an array.');
if (typeof wf.connections !== 'object') throw new Error('Invalid workflow: connections must be an object.');

const notionParentId = (form['Notion Parent Page ID'] || '').trim();
if (!notionParentId) throw new Error('Notion Parent Page ID is required.');

const clientName   = (form['Client Name'] || 'Client').trim();
const workflowName = (wf.name || 'Unnamed Workflow')
  .replace(/[\x00-\x1F\x7F]/g, '').replace(/[`*_#\[\]<>|]/g, ' ').trim()
  || 'Unnamed Workflow';

return [{ json: { wf, clientName, notionParentId, workflowName } }];

const { wf, clientName, notionParentId, workflowName } = $input.first().json;
const { nodes, connections } = wf;

// Build node maps
const byId   = Object.fromEntries(nodes.map(n => [n.id, n]));
const nameId = Object.fromEntries(nodes.map(n => [n.name, n.id]));
const adj    = Object.fromEntries(nodes.map(n => [n.id, []]));
const indeg  = Object.fromEntries(nodes.map(n => [n.id, 0]));

for (const [src, outs] of Object.entries(connections)) {
  const sid = nameId[src]; if (!sid) continue;
  for (const branches of Object.values(outs)) {
    if (!Array.isArray(branches)) continue;
    for (const branch of branches) {
      if (!Array.isArray(branch)) continue;
      for (const { node } of branch) {
        const tid = nameId[node]; if (!tid) continue;
        adj[sid].push(tid);
        indeg[tid]++;
      }
    }
  }
}

// Kahn's topological sort
const queue   = nodes.filter(n => indeg[n.id] === 0).map(n => n.id);
const sorted  = [];
const seen    = new Set();
while (queue.length) {
  const id = queue.shift();
  if (seen.has(id)) continue;
  seen.add(id); sorted.push(id);
  for (const nid of adj[id]) { if (--indeg[nid] === 0) queue.push(nid); }
}

const TRIGGERS = new Set(['n8n-nodes-base.webhook','n8n-nodes-base.scheduleTrigger',
  'n8n-nodes-base.manualTrigger','n8n-nodes-base.formTrigger',
  'n8n-nodes-base.emailReadImap','@n8n/n8n-nodes-langchain.chatTrigger']);

const cycleNodes = nodes.filter(n => !seen.has(n.id)).map(n => n.name);
const deadNodes  = nodes.filter(n => {
  return !connections[n.name] && !nodes.some(o => adj[o.id]?.includes(n.id))
         && !TRIGGERS.has(n.type);
}).map(n => n.name);

const ordered = [...sorted, ...cycleNodes.map(nm => nameId[nm]).filter(Boolean)]
  .map(id => byId[id]).filter(Boolean);

// Static audit
const findings = [];
const SECRETS = [
  [/sk-[a-zA-Z0-9]{20,}/,              'OpenAI API key'],
  [/xoxb-[a-zA-Z0-9-]+/,               'Slack bot token'],
  [/ghp_[a-zA-Z0-9]{36}/,              'GitHub PAT'],
  [/Bearer\s+[a-zA-Z0-9\-_.]{20,}/,    'hardcoded Bearer YOUR_TOKEN_HERE'],
];

for (const n of nodes) {
  const p = JSON.stringify(n.parameters || {});
  if (n.type === 'n8n-nodes-base.httpRequest' && !n.parameters?.options?.timeout)
    findings.push({ sev:'HIGH', node:n.name, issue:'HTTP Request has no timeout set.', fix:'Set Options › Timeout to 15000–30000 ms.' });
  for (const [re, label] of SECRETS)
    if (re.test(p)) findings.push({ sev:'CRITICAL', node:n.name, issue:`Possible hardcoded ${label}.`, fix:'Move to n8n Credentials.' });
  if (n.type === 'n8n-nodes-base.webhook' && (!n.parameters?.authentication || n.parameters.authentication === 'none'))
    findings.push({ sev:'HIGH', node:n.name, issue:'Webhook has no authentication.', fix:'Enable Header Auth or Basic Auth.' });
  if (n.type === '@n8n/n8n-nodes-langchain.agent' && !nodes.some(o => /approval|confirm|human/i.test(o.name)))
    findings.push({ sev:'MEDIUM', node:n.name, issue:'AI Agent has no human-in-the-loop step.', fix:'Add a Wait or approval node before destructive actions.' });
  if (['n8n-nodes-base.httpRequest','n8n-nodes-base.executeWorkflow'].includes(n.type)) {
    const hasErrNode = adj[n.id]?.some(id => byId[id]?.name?.toLowerCase().includes('error'));
    if (!hasErrNode) findings.push({ sev:'MEDIUM', node:n.name, issue:'No explicit error-handling node downstream.', fix:'Add an error branch or configure "On Error: Continue" with conditional logic.' });
  }
}
for (const nm of deadNodes)  findings.push({ sev:'LOW',    node:nm, issue:'Node is unreachable.', fix:'Remove or reconnect it.' });
for (const nm of cycleNodes) findings.push({ sev:'MEDIUM', node:nm, issue:'Node is in a cycle — sort order unresolved.', fix:'Ensure loops have an exit condition.' });

const score = Math.max(0, 100
  - findings.filter(f=>f.sev==='CRITICAL').length * 25
  - findings.filter(f=>f.sev==='HIGH').length     * 10
  - findings.filter(f=>f.sev==='MEDIUM').length   *  5
  - findings.filter(f=>f.sev==='LOW').length      *  2);

const nodeList = ordered.map((n,i) => {
  const ds = (adj[n.id]||[]).map(id=>byId[id]?.name).filter(Boolean);
  return `${i+1}. [${n.type}] "${n.name}"${ds.length ? ' → '+ds.join(', ') : ' (terminal)'}${cycleNodes.includes(n.name)?' ⚠ CYCLE':''}`;
}).join('\n');

const findingsSummary = findings.length
  ? findings.map(f=>`[${f.sev}] ${f.node}: ${f.issue} Fix: ${f.fix}`).join('\n')
  : 'No issues found.';

return [{ json: {
  workflowName, clientName, notionParentId,
  nodeCount: nodes.length, score,
  criticalCount: findings.filter(f=>f.sev==='CRITICAL').length,
  highCount:     findings.filter(f=>f.sev==='HIGH').length,
  mediumCount:   findings.filter(f=>f.sev==='MEDIUM').length,
  lowCount:      findings.filter(f=>f.sev==='LOW').length,
  findings, cycleNodes, deadNodes, hasCycles: cycleNodes.length > 0,
  nodeList, findingsSummary
} }];

const d = $input.first().json;

const system = `You are an automation consultant writing client documentation.

Return ONLY a raw JSON object with two keys — no markdown fences, no preamble:
{
  "businessLogic": "<150-300 word plain-English summary of what this workflow does, when it runs, and what outcomes it produces. No technical node names.>",
  "auditReport":   "<Developer-facing audit findings in Markdown. Bold each severity label. End with an overall assessment paragraph. If no findings, say so.>"
}`;

const user =
`Workflow: ${d.workflowName}
Client: ${d.clientName}
Nodes: ${d.nodeCount} | Audit Score: ${d.score}/100
${d.hasCycles ? 'WARNING: cycles detected in ' + d.cycleNodes.join(', ') : ''}

EXECUTION ORDER:
${d.nodeList}

AUDIT FINDINGS:
${d.findingsSummary}`;

return [{ json: { ...d, system, user } }];

const text = ($input.first().json.text || '').trim()
  .replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '');

if (!text) throw new Error('Model returned empty output.');

let parsed;
try   { parsed = JSON.parse(text); }
catch { throw new Error('Model did not return valid JSON: ' + text.substring(0, 200)); }

if (!parsed.businessLogic) throw new Error('Missing businessLogic in model response.');
if (!parsed.auditReport)   throw new Error('Missing auditReport in model response.');

const ctx = $('Construct AI Prompt').first().json;

return [{ json: {
  ...ctx,
  businessLogicMd: parsed.businessLogic,
  auditReportMd:   parsed.auditReport
} }];

const { workflowName, clientName, notionParentId, score,
        criticalCount, highCount, mediumCount, lowCount,
        nodeCount, businessLogicMd, auditReportMd,
        findings, hasCycles, cycleNodes, deadNodes } = $input.first().json;

const MAX = 1990;

function spans(text, ann={}) {
  const chunks = [];
  let s = String(text||'');
  while (s.length > MAX) {
    let i = s.lastIndexOf(' ', MAX); if (i < MAX*0.5) i = MAX;
    chunks.push(s.slice(0,i)); s = s.slice(i).trimStart();
  }
  if (s) chunks.push(s);
  return chunks.map(c => ({ type:'text', text:{content:c},
    annotations:{bold:false,italic:false,strikethrough:false,
                 underline:false,code:false,color:'default',...ann} }));
}

function mdToBlocks(md) {
  const out = []; let inCode=false, codeLines=[], lang='';
  for (const line of (md||'').split('\n')) {
    if (/^```/.test(line.trim())) {
      if (!inCode) { inCode=true; lang=line.trim().slice(3)||'plain text'; codeLines=[]; }
      else {
        inCode=false;
        const content=codeLines.join('\n');
        for(let i=0;i<content.length;i+=MAX)
          out.push({object:'block',type:'code',code:{language:lang,rich_text:[{type:'text',text:{content:content.slice(i,i+MAX)}}]}});
        codeLines=[]; lang='';
      }
      continue;
    }
    if (inCode) { codeLines.push(line); continue; }
    const t = line.trimEnd();
    if (!t) continue;
    if (/^### /.test(t)) { out.push({object:'block',type:'heading_3',heading_3:{rich_text:spans(t.slice(4))}}); continue; }
    if (/^## /.test(t))  { out.push({object:'block',type:'heading_2',heading_2:{rich_text:spans(t.slice(3))}}); continue; }
    if (/^# /.test(t))   { out.push({object:'block',type:'heading_1',heading_1:{rich_text:spans(t.slice(2))}}); continue; }
    if (/^[-*] /.test(t)){ out.push({object:'block',type:'bulleted_list_item',bulleted_list_item:{rich_text:spans(t.slice(2))}}); continue; }
    if (/^\d+\. /.test(t)){ out.push({object:'block',type:'numbered_list_item',numbered_list_item:{rich_text:spans(t.replace(/^\d+\. /,''))}}); continue; }
    if (/^---+$/.test(t)) { out.push({object:'block',type:'divider',divider:{}}); continue; }
    // paragraph with inline bold
    const parts=[]; const re=/\*\*(.+?)\*\*/g; let idx=0,m;
    while((m=re.exec(t))!==null){if(m.index>idx)parts.push(...spans(t.slice(idx,m.index)));parts.push(...spans(m[1],{bold:true}));idx=m.index+m[0].length;}
    if(idx<t.length)parts.push(...spans(t.slice(idx)));
    out.push({object:'block',type:'paragraph',paragraph:{rich_text:(parts.length?parts:spans(t)).slice(0,100)}});
  }
  return out;
}

const emoji  = score>=80?'✅':score>=50?'⚠️':'🔴';
const color  = score>=80?'green_background':score>=50?'yellow_background':'red_background';
const today  = new Date().toISOString().slice(0,10);

const blocks = [
  { object:'block',type:'callout',callout:{
    rich_text: spans(`${emoji} Audit Score: ${score}/100  ·  Critical: ${criticalCount}  High: ${highCount}  Medium: ${mediumCount}  Low: ${lowCount}  ·  ${clientName}  ·  ${today}`),
    color, icon:{type:'emoji',emoji}
  }},
  {object:'block',type:'divider',divider:{}},
  {object:'block',type:'heading_2',heading_2:{rich_text:spans('Business Logic Summary')}},
  ...mdToBlocks(businessLogicMd),
  {object:'block',type:'divider',divider:{}},
  {object:'block',type:'heading_2',heading_2:{rich_text:spans('Technical Audit Report')}},
  ...mdToBlocks(auditReportMd),
];

if (hasCycles || deadNodes?.length) {
  blocks.push({object:'block',type:'divider',divider:{}});
  blocks.push({object:'block',type:'heading_2',heading_2:{rich_text:spans('Graph Warnings')}});
  if (hasCycles)       blocks.push({object:'block',type:'callout',callout:{rich_text:spans('Cycles: '+cycleNodes.join(', ')),color:'orange_background',icon:{type:'emoji',emoji:'⚠️'}}});
  if (deadNodes?.length) blocks.push({object:'block',type:'callout',callout:{rich_text:spans('Unreachable: '+deadNodes.join(', ')),color:'yellow_background',icon:{type:'emoji',emoji:'🔸'}}});
}

blocks.push({object:'block',type:'divider',divider:{}});
blocks.push({object:'block',type:'paragraph',paragraph:{rich_text:[
  ...spans('Generated by '), ...spans('AutomiQ',{bold:true}), ...spans(' · automiq.fi · '+today)
]}});

const batches=[];
for(let i=0;i<blocks.length;i+=99) batches.push(blocks.slice(i,i+99));

return batches.map((b,i)=>({json:{notionParentId,workflowName,blocks:b,batchIndex:i,totalBatches:batches.length}}));
